1	import { cache } from "react";
2	import { resolvePriceForSubject } from "../resolve";
3	import type {
4	  Customer,
5	  CustomerGroup,
6	  PricingProfile,
7	  Product,
8	  ResolvedPrice,
9	} from "../types";
10	import {
11	  seedCustomerGroups,
12	  seedCustomers,
13	  seedProducts,
14	} from "./seed";
15	
16	type Store = {
17	  products: Map<string, Product>;
18	  customers: Map<string, Customer>;
19	  customerGroups: Map<string, CustomerGroup>;
20	  profiles: Map<string, PricingProfile>;
21	};
22	
23	declare global {
24	  // eslint-disable-next-line no-var
25	  var __foboh_store: Store | undefined;
26	}
27	
28	function createStore(): Store {
29	  const store: Store = {
30	    products: new Map(seedProducts.map((p) => [p.id, p])),
31	    customers: new Map(seedCustomers.map((c) => [c.id, c])),
32	    customerGroups: new Map(seedCustomerGroups.map((g) => [g.id, g])),
33	    profiles: new Map(),
34	  };
35	  return store;
36	}
37	
38	const store: Store = globalThis.__foboh_store ?? createStore();
39	if (!globalThis.__foboh_store) globalThis.__foboh_store = store;
40	
41	export type ProductFilters = {
42	  q?: string;
43	  category?: string;
44	  segment?: string;
45	  brand?: string;
46	};
47	
48	export const listProducts = cache(
49	  (filters: ProductFilters = {}): Product[] => {
50	    const q = filters.q?.trim().toLowerCase();
51	    const products = Array.from(store.products.values());
52	    return products.filter((p) => {
53	      if (q && !p.title.toLowerCase().includes(q) && !p.sku.toLowerCase().includes(q)) {
54	        return false;
55	      }
56	      if (filters.category && p.subCategory !== filters.category) return false;
57	      if (filters.segment && p.segment !== filters.segment) return false;
58	      if (filters.brand && p.brand !== filters.brand) return false;
59	      return true;
60	    });
61	  },
62	);
63	
64	export const getProduct = cache((id: string): Product | undefined =>
65	  store.products.get(id),
66	);
67	
68	export const listCustomers = cache((): Customer[] =>
69	  Array.from(store.customers.values()),
70	);
71	
72	export const getCustomer = cache((id: string): Customer | undefined =>
73	  store.customers.get(id),
74	);
75	
76	export const listCustomerGroups = cache((): CustomerGroup[] =>
77	  Array.from(store.customerGroups.values()),
78	);
79	
80	export const listProfiles = cache((): PricingProfile[] =>
81	  Array.from(store.profiles.values()),
82	);
83	
84	export const getProfile = cache((id: string): PricingProfile | undefined =>
85	  store.profiles.get(id),
86	);
87	
88	export function createProfile(
89	  data: Omit<PricingProfile, "id" | "createdAt" | "updatedAt">,
90	): PricingProfile {
91	  const now = new Date().toISOString();
92	  const id = `prof_${Math.random().toString(36).slice(2, 10)}`;
93	  const profile: PricingProfile = {
94	    ...data,
95	    id,
96	    createdAt: now,
97	    updatedAt: now,
98	  };
99	  store.profiles.set(id, profile);
100	  return profile;
101	}
102	
103	export function updateProfile(
