              "application/json": {
                schema: {
                  type: "object",
                  required: ["profile"],
                  properties: { profile: ref("PricingProfile") },
                },
              },
            },
          },
          "404": errorResponse("Profile not found"),
        },
      },
      put: {
        tags: ["Pricing Profiles"],
        summary: "Update a pricing profile",
        description:
